//! Criterion benchmarks for the tag-reading/writing hot paths.
//!
//! These read fixtures from `bench-data/` (generated by `scripts/gen-corpus.sh`,
//! git-ignored). Benches whose corpus is missing are skipped with a note, so
//! `cargo bench` works on a fresh checkout (it just measures less). Run:
//!
//!   scripts/gen-corpus.sh              # generate corpora first
//!   cargo bench --manifest-path src-tauri/Cargo.toml
//!
//! See PLAN.md §4.3.

use audiotag_lib::tags::{
    read_track, read_track_opt, scan_files_for_bench, scan_paths, write_track, Track,
};
use criterion::{criterion_group, criterion_main, Criterion, Throughput};
use std::path::{Path, PathBuf};

/// Repository `bench-data/` directory (../../bench-data relative to src-tauri).
fn data_dir() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .unwrap()
        .join("bench-data")
}

/// First file with the given extension under `dir`, if any.
fn first_with_ext(dir: &Path, ext: &str) -> Option<PathBuf> {
    if !dir.is_dir() {
        return None;
    }
    walkdir::WalkDir::new(dir)
        .into_iter()
        .filter_map(|e| e.ok())
        .map(|e| e.into_path())
        .find(|p| p.extension().and_then(|e| e.to_str()) == Some(ext))
}

/// `read_track` over one representative file of each format, A/B'ing audio
/// property parsing on vs off (Phase 1). `read_track` itself uses props-off.
fn bench_read_per_format(c: &mut Criterion) {
    let mixed = data_dir().join("mixed-format");
    let mut group = c.benchmark_group("read_track_per_format");
    let formats = ["mp3", "flac", "m4a", "ogg", "opus", "wav", "aiff", "wv"];
    let mut any = false;
    for fmt in formats {
        if let Some(p) = first_with_ext(&mixed, fmt) {
            any = true;
            group.bench_function(format!("{fmt}/props_on"), |b| {
                b.iter(|| read_track_opt(std::hint::black_box(&p), true))
            });
            group.bench_function(format!("{fmt}/props_off"), |b| {
                b.iter(|| read_track_opt(std::hint::black_box(&p), false))
            });
        }
    }
    if !any {
        eprintln!("skip read_track_per_format: bench-data/mixed-format missing (run scripts/gen-corpus.sh)");
    }
    group.finish();
}

/// `read_track` over art-bearing files. Cover art is materialized either way
/// (needed for `has_art`); this isolates the property-parsing delta on big
/// files and documents the cover-materialization cost the streaming/concurrency
/// phases bound the RSS of. See PLAN.md H3.
fn bench_read_art(c: &mut Criterion) {
    let art = data_dir().join("art-heavy");
    let mut group = c.benchmark_group("read_track_art");
    let mut any = false;
    for fmt in ["flac", "mp3", "m4a"] {
        if let Some(p) = first_with_ext(&art, fmt) {
            any = true;
            group.bench_function(format!("{fmt}/props_on"), |b| {
                b.iter(|| read_track_opt(std::hint::black_box(&p), true))
            });
            group.bench_function(format!("{fmt}/props_off"), |b| {
                b.iter(|| read_track_opt(std::hint::black_box(&p), false))
            });
        }
    }
    if !any {
        eprintln!("skip read_track_art: bench-data/art-heavy missing (run scripts/gen-corpus.sh art-heavy)");
    }
    group.finish();
}

/// Full `scan_paths` over the available corpora (walk + filter + sort + read).
fn bench_scan(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_paths");
    group.sample_size(10);
    for corpus in ["tiny", "small", "medium", "large"] {
        let dir = data_dir().join(corpus);
        if !dir.is_dir() {
            continue;
        }
        let count = walkdir::WalkDir::new(&dir)
            .into_iter()
            .filter_map(|e| e.ok())
            .filter(|e| e.file_type().is_file())
            .count();
        group.throughput(Throughput::Elements(count as u64));
        let path = dir.to_string_lossy().into_owned();
        group.bench_function(corpus, |b| {
            b.iter(|| scan_paths(std::hint::black_box(vec![path.clone()])))
        });
    }
    group.finish();
}

/// `write_track` over a temp copy of each format template (so the bench is
/// repeatable and doesn't mutate the corpus). Measures re-read + write.
fn bench_write(c: &mut Criterion) {
    let mixed = data_dir().join("mixed-format");
    let mut group = c.benchmark_group("write_track");
    let mut any = false;
    for fmt in ["mp3", "flac", "m4a", "ogg", "wav"] {
        let Some(src) = first_with_ext(&mixed, fmt) else {
            continue;
        };
        any = true;
        let tmp = std::env::temp_dir().join(format!("audiotag_bench_write.{fmt}"));
        std::fs::copy(&src, &tmp).expect("copy template for write bench");
        let mut track = read_track(&tmp);
        track.title = Some("Edited Title".into());
        track.artist = Some("Edited Artist".into());
        group.bench_function(fmt, |b| {
            b.iter(|| write_track(std::hint::black_box(&track)))
        });
        let _ = std::fs::remove_file(&tmp);
    }
    if !any {
        eprintln!("skip write_track: bench-data/mixed-format missing (run scripts/gen-corpus.sh)");
    }
    group.finish();
}

/// Sequential vs bounded-parallel reading over a corpus (Phase 6 A/B). Decides
/// whether bounded concurrency is a real win on this machine/disk.
fn bench_scan_parallel(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_parallel");
    group.sample_size(10);
    for corpus in ["medium", "large", "art-heavy"] {
        let dir = data_dir().join(corpus);
        if !dir.is_dir() {
            continue;
        }
        let paths = vec![dir.to_string_lossy().into_owned()];
        for workers in [1usize, 4, 8] {
            group.bench_function(format!("{corpus}/w{workers}"), |b| {
                b.iter(|| scan_files_for_bench(std::hint::black_box(&paths), workers))
            });
        }
    }
    group.finish();
}

criterion_group!(
    benches,
    bench_read_per_format,
    bench_read_art,
    bench_scan,
    bench_scan_parallel,
    bench_write
);
criterion_main!(benches);

// Keep the `Track` import used even if a bench above is commented out.
#[allow(dead_code)]
fn _type_check(_: Track) {}
